import React, { useState, useEffect } from "react";
import "./App.css";
import mondaySdk from "monday-sdk-js";
import "monday-ui-react-core/dist/main.css";
import ListInputMod from "./modules/ListInputMod.js";
import { AlertBanner, AlertBannerText, AlertBannerLink, Toast } from "monday-ui-react-core";


const monday = mondaySdk();
const redirect_uri = "https://e47171547284.ngrok.app";
const client_id = "eb18d6836553020a3107559d979d31a8";
const client_secret = "ae0b0f705f2a9d99967c68fe1e61f308";

const App = () => {
  const [token, setToken] = useState(null);
  const [showBanner, setShowBanner] = useState(false);
  const [isViewOnly, setIsViewOnly] = useState(false);
  const [showToast, setShowToast] = useState(false);

  useEffect(() => {
    setShowBanner(true);
    const storedToken = localStorage.getItem('mondayToken');
    if (storedToken) {
      setToken(storedToken);
      monday.setToken(storedToken);
      monday.api(`query { me { is_view_only }}`)
        .then(res => {
          if (!res.data || !res.data.me) {
            console.error('Invalid API response:', res);
            return;
          }
          setIsViewOnly(res.data.me.is_view_only);
          if (res.data.me.is_view_only) {
            setShowToast(true);
          }
        })
        .catch(err => {
          console.error('Error fetching view-only status:', err);
          // Set a default value in case of error
          setIsViewOnly(true); // Default to view-only for safety
          setShowToast(true);
        });
      console.log("Token retrieved from storage");
    } else {
      const urlParams = new URLSearchParams(window.location.search);
      const code = urlParams.get("code");
      if (code) {
        fetch('https://df5ac29b691e.ngrok.app/oauth/token', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            client_id: client_id,
            client_secret: client_secret,
            code: code,
            redirect_uri: redirect_uri,
          }),
        })
        .then(response => response.json())
        .then(data => {
          if (data.access_token) {
            setToken(data.access_token);
            localStorage.setItem('mondayToken', data.access_token);
            monday.setToken(data.access_token);
            monday.api(`query { me { is_view_only }}`)
              .then(res => {
                setIsViewOnly(res.data.me.is_view_only);
                if (res.data.me.is_view_only) {
                  setShowToast(true);
                }
              });
            setShowBanner(true);
            window.history.replaceState({}, document.title, "/");
          }
        });
      } else {
        window.location.href = `https://auth.monday.com/oauth2/authorize?client_id=${client_id}&redirect_uri=${encodeURIComponent(redirect_uri)}&response_type=code`;
      }
    }
  }, []);

  return (
    <div className="App container">
      {showToast && (
        <Toast
          open={showToast}
          type={Toast.types.NEGATIVE}
          autoHideDuration={5000}
          onClose={() => setShowToast(false)}
        >
          As a viewer, you are unable to use this app.
        </Toast>
      )}
      <div className="container">
        <div className="row">
          {showBanner && (
            <Toast
              open={showBanner}
              type={Toast.types.POSITIVE}
              autoHideDuration={5000}
              onClose={() => setShowBanner(false)}
            >
              Welcome! Check out our <a href="https://rallyessentials.com/documentation/" style={{color: 'inherit', textDecoration: 'underline'}}> documentation </a> to help you get started.
            </Toast>
          )}
        </div>
        <div className="row">
          <div className="col-12">
            <ListInputMod />
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
